    "generation": "نسل دوم (U10)",
    "imageUrl": "https://cdn-sth1.bama.ir/uploads/BamaImages/Research/b38ae8da-c107-4487-a0ff-b47d69d602e1/research_638895781995867879.jpg?x-img=v1/format,type_webp/autorotate/resize,w_450",
