    "slug": "opel-astrasedan",
    "manufacturer": "اپل",
    "model": "آسترا سدان 1.4 لیتر",
    "generation": "نسل چهارم (P10)",
    "imageUrl": "https://cdn-sth1.bama.ir/uploads/BamaImages/Research/00df2d07-7bf7-4034-8803-2e8570a351b9/research_637388196623488421.jpg?x-img=v1/format,type_webp/autorotate/resize,w_450",
    "engineType": "4 سیلندر توربوشارژ ECOTEC",
