    "imageUrl": "https://cdn-sth1.bama.ir/uploads/BamaImages/Research/cd6d7291-89aa-4d41-a85e-837df82564c9/research_638596797594543095.jpg?x-img=v1/format,type_webp/autorotate/resize,w_450",
